parameters.jsCode:
const items = $input.all();

// Her LLM'in çıktısını node adına göre ayır
const quality    = items.find(i => i.json.llm_role === 'quality')?.json;
const compliance = items.find(i => i.json.llm_role === 'compliance')?.json;
const security   = items.find(i => i.json.llm_role === 'security')?.json;

return [{
  json: {
    quality_llm_output:  quality,
    compliance_llm_output:  compliance,
    security_llm_output:  security,
  }
}];

// n8n Code node — Input: $json (hakem LLM output)
const r = $input.first().json.output
const report = r.report;
const passed = r.verdict === "approved";
const ts = new Date().toISOString().replace('T', ' ').substring(0, 19);

const scoreBar = (score, threshold) => {
  const filled = Math.round(score / 10);
  const bar = '█'.repeat(filled) + '░'.repeat(10 - filled);
  const status = score >= threshold ? '✅' : '❌';
  return `${status} \`${bar}\` ${score}/100  _(threshold: ${threshold})_`;
};

const bulletList = (items) => items.map(i => `- ${i}`).join('\n');

const md = `# Commit Review Report

${passed ? '## ✅ APPROVED' : '## ❌ REJECTED'}
${!passed ? `\n> **Rejection reason:** ${r.reject_reason}\n` : ''}
---

## Commit Details

| Field | Value |
|---|---|
| **Author** | ${r.commit_metadata.author} |
| **Date** | ${r.commit_metadata.timestamp} |
| **Repo / Branch** | ${r.commit_metadata.repo} / \`${r.commit_metadata.branch}\` |
| **Message** | ${r.commit_metadata.message} |
| **Files Changed** | ${r.commit_metadata.files_changed.join(', ')} |

---

## Scores

| Category | Score | Threshold | Status |
|---|---|---|---|
| Code Quality | ${r.scores.quality}/100 | ${r.thresholds.quality.required} | ${r.thresholds.quality.passed ? '✅' : '❌'} |
| Compliance | ${r.scores.compliance}/100 | ${r.thresholds.compliance.required} | ${r.thresholds.compliance.passed ? '✅' : '❌'} |
| Security | ${r.scores.security}/100 | ${r.thresholds.security.required} | ${r.thresholds.security.passed ? '✅' : '❌'} |

${scoreBar(r.scores.quality, r.thresholds.quality.required)} — Quality  
${scoreBar(r.scores.compliance, r.thresholds.compliance.required)} — Compliance  
${scoreBar(r.scores.security, r.thresholds.security.required)} — Security  

---

## Executive Summary

${report.executive_summary}

---

## Code Quality  —  ${r.scores.quality}/100

**Key findings:**
${bulletList(report.quality_section.key_findings)}

**Action items:**
${bulletList(report.quality_section.action_items)}

---

## Standards Compliance  —  ${r.scores.compliance}/100

**Key findings:**
${bulletList(report.compliance_section.key_findings)}

**Action items:**
${bulletList(report.compliance_section.action_items)}

---

## Security Analysis  —  ${r.scores.security}/100

**Key findings:**
${bulletList(report.security_section.key_findings)}

**Action items:**
${bulletList(report.security_section.action_items)}

---

## Referee Notes

${report.referee_notes}

---

## Priority Action Items

${report.priority_action_items.map(i => `- ${i}`).join('\n')}

---

_Generated: ${ts}_
`;

return { md, verdict: r.verdict};
